// ============================================================================
// 📱 KODA — Extraire infos du message WhatsApp entrant
// Identique au pattern Stella, adapté pour Koda
// ============================================================================

const body = $input.item.json.body;

const entry = body?.entry?.[0];
const changes = entry?.changes?.[0];
const value = changes?.value;
const messages = value?.messages;

// Si pas de messages → status update (delivered, read, sent)
if (!messages || messages.length === 0) {
  return { json: { skip: true, body: '', from: '', phoneNumber: '', profileName: '', prenom: '', messageId: '', timestamp: '', phoneNumberId: '' } };
}

const message = messages[0];
const contacts = value?.contacts?.[0];

const from = message.from;
const phoneNumber = '+' + from;
const profileName = contacts?.profile?.name || '';
const prenom = profileName ? profileName.split(' ')[0] : '';
const messageId = message.id;
const timestamp = message.timestamp;

let messageBody = '';
if (message.type === 'text') {
  messageBody = message.text?.body || '';
} else if (message.type === 'button') {
  messageBody = message.button?.text || '';
} else if (message.type === 'interactive') {
  messageBody = message.interactive?.button_reply?.title || message.interactive?.list_reply?.title || '';
} else if (message.type === 'image') {
  messageBody = '[Image envoyée]';
} else if (message.type === 'document') {
  messageBody = '[Document envoyé]';
} else if (message.type === 'audio') {
  messageBody = '[Message vocal]';
} else {
  messageBody = `[Message de type ${message.type}]`;
}

// Phone Number ID Koda
const phoneNumberId = value?.metadata?.phone_number_id || '1107773802412902';

return {
  json: {
    skip: false,
    from,
    phoneNumber,
    profileName,
    prenom,
    body: messageBody,
    messageId,
    timestamp,
    phoneNumberId
  }
};

// ============================================================================
// 🧠 KODA — Construire le contexte pour l'agent IA
// Rassemble : infos WA + profil jeune + état onboarding + historique
// ============================================================================

const waData = $('Extraire infos WhatsApp').item.json;
const lookupResults = $('🔍 Chercher jeune dans Supabase').all();
const jeune = lookupResults.length > 0 ? lookupResults[0].json : null;

const isKnown = !!jeune;
const prenom = jeune?.prenom || waData.prenom || waData.profileName?.split(' ')[0] || '';
const onboardingStep = jeune?.onboarding_step || 'not_started';
const currentStage = jeune?.current_stage || 'new';
const dataCollected = jeune?.data_collected || {};

// Construire le contexte structuré pour l'agent
let context = '';

if (!isKnown) {
  context = `NOUVEAU CONTACT — Ce numéro (${waData.from}) n'est pas dans la base Supabase.
Le profil WhatsApp s'appelle : ${waData.profileName || 'inconnu'}.
C'est peut-être un jeune qu'on n'a pas encore enregistré, ou un numéro différent.
Demande-lui son prénom et oriente-le. Si c'est un jeune accompagné par Les Ombres, dis-lui de te donner son prénom pour qu'on le retrouve.`;
} else {
  context = `JEUNE IDENTIFIÉ :
- Prénom : ${prenom}
- Airtable ID : ${jeune.airtable_id}
- Secteur visé : ${jeune.secteur_vise || 'Non précisé'}
- Ville/Département : ${jeune.ville || ''} ${jeune.departement || ''}
- Classe : ${jeune.classe || 'Non précisé'}
- Français : ${jeune.niveau_francais_declare || 'Non précisé'}
- MNA : ${jeune.mna ? 'Oui' : 'Non'}
- Disponibilité : ${jeune.disponibilite || 'Non précisée'}
- Besoins exprimés : ${jeune.besoins || 'Non précisés'}
- Attentes mentor : ${jeune.attentes_mentor || 'Non précisées'}
- Codes ROME : ${jeune.codes_rome_suggeres || 'Non définis'}

ÉTAT AGENT : ${currentStage}
ONBOARDING : étape "${onboardingStep}"
`;

  // Données déjà collectées pendant l'onboarding
  if (Object.keys(dataCollected).length > 0) {
    context += `\nDonnées déjà collectées pendant l'onboarding :\n`;
    for (const [k, v] of Object.entries(dataCollected)) {
      context += `- ${k}: ${v}\n`;
    }
  }

  // Matchs en attente
  if (jeune.pending_matches && Array.isArray(jeune.pending_matches) && jeune.pending_matches.length > 0) {
    context += `\nMATCHS EN ATTENTE (${jeune.pending_matches.length}) :\n`;
    jeune.pending_matches.forEach((m, i) => {
      context += `${i+1}. ${m.titre} chez ${m.entreprise} (${m.lieu}) — Score: ${m.score}\n`;
    });
  }

  // Instructions selon l'étape d'onboarding
  if (onboardingStep === 'not_started' || onboardingStep === 'welcome') {
    context += `\nINSTRUCTION : C'est le premier échange avec ce jeune. Présente-toi et lance l'onboarding : demande-lui ce qu'il cherche comme travail.`;
  } else if (onboardingStep === 'job_type' || onboardingStep === 'job_type_confirm') {
    context += `\nINSTRUCTION : On attend que le jeune précise son secteur/métier recherché. Analyse sa réponse et passe à la question de localisation.`;
  } else if (onboardingStep === 'location' || onboardingStep === 'location_confirm') {
    context += `\nINSTRUCTION : On attend la localisation. Puis demande le type de contrat recherché (CDI/CDD, alternance, stage, tout).`;
  } else if (onboardingStep === 'contract_type') {
    context += `\nINSTRUCTION : On attend le type de contrat. Puis demande s'il a un CV.`;
  } else if (onboardingStep === 'cv_check') {
    context += `\nINSTRUCTION : On attend de savoir s'il a un CV. Si oui, super. Si non, dis-lui qu'on peut l'aider à en créer un. Puis fais un récap de tout ce qu'on sait et dis-lui que tu lances les recherches.`;
  } else if (onboardingStep === 'ready') {
    context += `\nINSTRUCTION : L'onboarding est terminé. Le jeune est en mode normal. Réponds à sa question, propose des offres si tu en as, aide-le sur ses candidatures.`;
  }
}

// Ajouter l'airtable_id en fin de contexte pour que l'agent puisse le passer au tool
if (isKnown) {
  context += `\n\nIDENTIFIANT INTERNE : ${jeune.airtable_id}`;
  context += `\nQuand tu appelles search_job_offers, passe exactement cet identifiant : ${jeune.airtable_id}`;
}

return {
  json: {
    ...waData,
    isKnown,
    jeuneId: jeune?.airtable_id || null,
    jeunePrenom: prenom,
    onboardingStep,
    currentStage,
    context
  }
};

// ============================================================================
// 📤 KODA — Assembler réponse + Logger dans Supabase
// ============================================================================

const input = $input.item.json;
const waData = $('🧠 Construire contexte Koda').item.json;

let reponseIA = '';
try {
  reponseIA = input.output || input.text || '';
} catch (e) {
  reponseIA = "Merci pour ton message ! Je reviens vers toi très vite.";
}

// Nettoyer
reponseIA = reponseIA
  .replace(/^(Bonjour|Salut|Hello|Hey|Coucou)\s+\w+[,!]?\s*/i, '')
  .replace(/\n*(Cordialement|À bientôt|Koda|Assistant)[^\n]*$/gi, '')
  .replace(/\*\*/g, '')
  .replace(/\*/g, '')
  .trim();

// Construire les SQL de logging
const esc = (v) => {
  if (v === null || v === undefined) return 'NULL';
  return "'" + String(v).replace(/'/g, "''").substring(0, 5000) + "'";
};
const now = new Date().toISOString();
const jeuneId = waData.jeuneId;

let sqlStatements = [];

if (jeuneId) {
  // Log message entrant
  sqlStatements.push(`INSERT INTO koda_conversations (jeune_id, direction, sender, message_text, message_type, wa_message_id, metadata) VALUES (${esc(jeuneId)}, 'in', 'jeune', ${esc(waData.body)}, 'text', ${esc(waData.messageId)}, '{"wa_phone":"${waData.from}"}'::jsonb) ON CONFLICT (wa_message_id) WHERE wa_message_id IS NOT NULL DO NOTHING;`);

  // Log message sortant
  sqlStatements.push(`INSERT INTO koda_conversations (jeune_id, direction, sender, message_text, message_type) VALUES (${esc(jeuneId)}, 'out', 'koda', ${esc(reponseIA)}, 'text');`);

  // Memory stream
  sqlStatements.push(`INSERT INTO koda_memory_stream (jeune_id, event_type, source, content, metadata, importance) VALUES (${esc(jeuneId)}, 'message_in', 'jeune', ${esc(waData.body)}, '{"wa_phone":"${waData.from}","onboarding_step":"${waData.onboardingStep}"}'::jsonb, 3);`);

  // Mettre à jour agent state
  sqlStatements.push(`UPDATE koda_agent_state SET last_message_at = '${now}', last_reply_at = '${now}', wa_phone = '${waData.from}', updated_at = '${now}' WHERE jeune_id = ${esc(jeuneId)};`);

  // Avancement onboarding
  const step = waData.onboardingStep;
  let newStep = step;
  if (step === 'not_started' || step === 'welcome') newStep = 'job_type';
  else if (step === 'job_type' || step === 'job_type_confirm') newStep = 'location';
  else if (step === 'location' || step === 'location_confirm') newStep = 'contract_type';
  else if (step === 'contract_type') newStep = 'cv_check';
  else if (step === 'cv_check') newStep = 'ready';

  if (newStep !== step) {
    let dataKey = '';
    if (step === 'job_type' || step === 'job_type_confirm') dataKey = 'secteur_stated';
    else if (step === 'location' || step === 'location_confirm') dataKey = 'location_stated';
    else if (step === 'contract_type') dataKey = 'contract_type';
    else if (step === 'cv_check') dataKey = 'has_cv';

    const dataUpdate = dataKey ? `data_collected = data_collected || '{"${dataKey}":${esc(waData.body)}}'::jsonb,` : '';
    sqlStatements.push(`UPDATE koda_onboarding_state SET step = '${newStep}', ${dataUpdate} ${newStep === 'ready' ? "completed_at = '" + now + "'," : ''} started_at = COALESCE(started_at, '${now}'), updated_at = '${now}' WHERE jeune_id = ${esc(jeuneId)};`);
  }
}

return {
  json: {
    to: waData.from,
    messageWhatsApp: reponseIA,
    phoneNumber: waData.phoneNumber,
    profileName: waData.profileName,
    phoneNumberId: waData.phoneNumberId,
    jeuneId: jeuneId,
    sqlStatements: sqlStatements.join('\n')
  }
};

