// ============================================================
// 🔍 Détecter si un CV doit être généré
// Vérifie : conversation parle de CV + email collecté
// ============================================================

const waData = $('🧠 Construire contexte Koda').item.json;
const agentResponse = $('📤 Assembler réponse + Logger').item.json;
const recentMessages = (waData.body || '').toLowerCase();
const agentText = (agentResponse.messageWhatsApp || '').toLowerCase();
const jeuneId = waData.jeuneId;

// Détecter si l'agent a fini la collecte CV
const agentSaysReady = agentText.includes('je prépare ton cv') 
  || agentText.includes("j'ai tout ce qu'il faut")
  || agentText.includes('je te l\'envoie');

// Détecter si le contexte parle de CV
const cvTopicInConversation = recentMessages.includes('cv') 
  || recentMessages.includes('curriculum');

const shouldGenerateCV = agentSaysReady && jeuneId;

return [{
  json: {
    ...agentResponse,
    shouldGenerateCV,
    jeuneId: jeuneId,
    wa_phone: waData.from,
    phoneNumberId: waData.phoneNumberId,
    // Passer tout le contexte de la conversation pour le CV
    cvContext: shouldGenerateCV ? (waData.context || '') : ''
  }
}];

// Préparer les données pour le sous-workflow CV
const data = $('🔍 Détecter CV à générer').first().json;

// Le sous-workflow attend { query: "airtable_id | contexte" }
// On passe l'ID + toute la conversation comme contexte
const conversations = $('🧠 Construire contexte Koda').item.json.context || '';

return [{ json: { 
  query: data.jeuneId + ' | ' + conversations.substring(0, 2000)
} }];

